def tipo_dato_esquema(campo):
    c = (campo or '').lower()
    if 'fecha' in c:
        return 'DateTime'
    if 'remun' in c or 'meses' in c or 'numero' in c:
        return 'Numeric'
    return 'Text'


def nombre_legible_campo(campo):
    return re.sub(r'(?<!^)(?=[A-ZÁÉÍÓÚÑ])', ' ', campo or '').strip() or campo

