def fotocheck_get(row, key, default=''):
    try:
        if row is not None and hasattr(row, 'keys') and key in row.keys():
            return row[key] if row[key] is not None else default
        if isinstance(row, dict):
            return row.get(key, default)
    except Exception:
        pass
    return default


