def get_trabajador(dni):
    dni = normalizar_dni(dni)
    with db() as con:
        return con.execute("SELECT * FROM trabajadores WHERE dni=?", (dni,)).fetchone()



def row_get(row, key, default=''):
    try:
        return row[key] if row and key in row.keys() and row[key] is not None else default
    except Exception:
        return default





def validar_dni_en_requerimiento(con, dni, requerimiento):
    """Valida que exista un postulante activo con DNI dentro del requerimiento seleccionado."""
    dni = normalizar_dni(dni)
    requerimiento = clean(requerimiento)
    if not requerimiento:
        return False, 'Primero seleccione un requerimiento/requerimiento.', None
    if not dni:
        return False, 'Digite un DNI válido de 8 dígitos.', None
    row = con.execute("""SELECT * FROM contratacion_ingresos
                         WHERE dni=? AND TRIM(COALESCE(requerimiento,''))=TRIM(?)
                           AND UPPER(COALESCE(estado,'')) NOT IN ('ANULADO','CANCELADO')
                         ORDER BY id DESC LIMIT 1""", (dni, requerimiento)).fetchone()
    if not row:
        return False, f'El DNI {dni} no pertenece al requerimiento {requerimiento}. Primero regístrelo en Postulantes/Requerimiento.', None
    return True, '', row

def existe_registro_modulo(con, tabla, dni, requerimiento):
    dni = normalizar_dni(dni)
    requerimiento = clean(requerimiento)
    try:
        return con.execute(f"SELECT id FROM {tabla} WHERE dni=? AND TRIM(COALESCE(requerimiento,''))=TRIM(?) LIMIT 1", (dni, requerimiento)).fetchone() is not None
    except Exception:
        return False

def validar_prendas_indumentaria(form):
    campos = ['polo','pantalon','botas','casaca','gorro','lentes','guantes','fotocheck','otros']
    return any(clean(form.get(c)) for c in campos)




# =============================
# VALIDACIONES DE FLUJO OPERATIVO CONTRATACIÓN
# Postulantes -> Evaluación Médica -> Inducción -> Indumentaria
# =============================
def flujo_postulante_completo(row):
    """Solo deja avanzar a módulos posteriores si la ficha de Postulantes está registrada y completa."""
    if not row:
        return False
    dni = normalizar_dni(row_get(row, 'dni'))
    trabajador = clean(row_get(row, 'trabajador'))
    if not dni or not trabajador or trabajador.upper() in ('PENDIENTE COMPLETAR', 'NUEVO - PENDIENTE COMPLETAR'):
        return False
    try:
        return len(campos_faltantes_postulante(row)) == 0
    except Exception:
        # Respaldo mínimo si cambia el esquema: no permitir avance sin datos base.
        minimos = ['dni', 'trabajador', 'empresa', 'area', 'cargo', 'actividad', 'requerimiento']
        return all(not es_valor_incompleto(row_get(row, c)) for c in minimos)


def flujo_medica_apta_con(con, dni, requerimiento):
    """Valida evaluación médica apta/habilitada para el requerimiento exacto."""
    dni = normalizar_dni(dni)
    requerimiento = clean(requerimiento)
    if not dni or not requerimiento:
        return False
    r = con.execute("""SELECT estado, aptitud FROM contratacion_medica
                       WHERE dni=? AND TRIM(COALESCE(requerimiento,''))=TRIM(?)
                       ORDER BY id DESC LIMIT 1""", (dni, requerimiento)).fetchone()
    if not r:
        return False
    estado = estado_norm(row_get(r, 'estado'))
    aptitud = estado_norm(row_get(r, 'aptitud'))
    return estado in ('APTO', 'HABILITADO', 'APROBADO') or aptitud in ('APTO', 'APTO CON RESTRICCIONES', 'HABILITADO', 'APROBADO')


def flujo_induccion_ok(row):
    return estado_norm(row_get(row, 'estado_capacitacion')) in ('VIDEO VISTO', 'APROBADO', 'INDUCIDO', 'COMPLETO', 'COMPLETADO', 'OK')


def flujo_indumentaria_ok(row):
    return estado_norm(row_get(row, 'estado_indumentaria')) in ('ENTREGADO', 'COMPLETO', 'COMPLETADO', 'OK')



def modulos_faltantes_postulante(row, medico_ok=None):
    """Devuelve avance estándar para las listas de todos los módulos."""
    faltan = []
    try:
        if not flujo_postulante_completo(row):
            faltan.append('Postulantes')
    except Exception:
        faltan.append('Postulantes')
    try:
        if medico_ok is None:
            med = estado_norm(row_get(row, 'estado_medico'))
            apt = estado_norm(row_get(row, 'aptitud_medica'))
            medico_ok = med in ('APTO','HABILITADO','APROBADO') or apt in ('APTO','HABILITADO','APROBADO','APTO CON RESTRICCIONES')
        if not medico_ok:
            faltan.append('Evaluación médica')
    except Exception:
        faltan.append('Evaluación médica')
    if not flujo_induccion_ok(row):
        faltan.append('Inducción')
    if not flujo_indumentaria_ok(row):
        faltan.append('Indumentaria')
    if estado_norm(row_get(row, 'fotocheck_estado')) not in ('ENTREGADO','IMPRESO','CARGO GENERADO','LISTO PARA IMPRIMIR','FOTO APROBADA','OK'):
        faltan.append('Fotocheck')
    if estado_norm(row_get(row, 'estado_documentos')) not in ('FIRMADO','COMPLETO','COMPLETADO','APROBADO','OK'):
        faltan.append('Contratos')
    pct = max(0, int(round((6 - len(faltan)) * 100 / 6)))
    estado = 'COMPLETO' if not faltan else ('EN PROCESO' if pct else 'PENDIENTE')
    return estado, pct, faltan


def acciones_estandar_postulante(row, req='', extra=''):
    """Iconos estándar: ojo detalle, lápiz editar, hojita ficha impresión y tres puntitos a postulantes."""
    dni = h(row_get(row, 'dni'))
    rid = h(row_get(row, 'id'))
    req_val = h(req or row_get(row, 'requerimiento'))
    return (f"<div class='std-actions'>"
            f"<a class='std-ico' title='Ver detalle del postulante' href='/admin/contratacion?sec=detalle_postulante&id={rid}'>👁️</a>"
            f"<a class='std-ico' title='Editar / modificar' href='/admin/contratacion?sec=nuevos&req={req_val}&dni={dni}'>✏️</a>"
            f"<a class='std-ico' title='Ver ficha para impresión' target='_blank' href='/admin/contratacion?sec=detalle_postulante&id={rid}&print=1'>📄</a>"
            f"<a class='std-ico' title='Ir a postulantes' href='/admin/contratacion?sec=nuevos&req={req_val}'>⋯</a>{extra}</div>")


def _std_estado_modulo(txt='', ok_words=(), warn_words=()):
    v = estado_norm(txt)
    if ok_words and v in ok_words:
        return "<span class='std-check ok'>✅</span>"
    if warn_words and v in warn_words:
        return "<span class='std-check warn'>➖</span>"
    return "<span class='std-check pend'>➖</span>"


def _std_mod_cell(icono, texto, cls='pendiente'):
    return f"<span class='std-mod {cls}'><b>{icono}</b><small>{h(texto)}</small></span>"


def fila_estandar_postulante(row, req='', medico_ok=None, checkbox_name='ingreso_ids', extra_action='', idx=''):
    """Fila premium estándar para módulos operativos: Inducción, Indumentaria y Fotocheck.
    Mantiene selección antes de acciones y columnas uniformes como la vista premium solicitada.
    """
    estado, pct, faltan = modulos_faltantes_postulante(row, medico_ok=medico_ok)
    cls = 'ok' if estado == 'COMPLETO' else ('warn' if pct else 'bad')
    rid = h(row_get(row, 'id'))
    dni = h(row_get(row, 'dni'))
    trabajador = h(row_get(row, 'trabajador') or 'PENDIENTE COMPLETAR')
    cargo = h(row_get(row, 'cargo'))
    foto_icon = '🧑🏻' if clean(row_get(row,'foto_ruta')) else '👤'

    med_txt = estado_norm(row_get(row,'estado_medico') or row_get(row,'aptitud_medica'))
    med_ok = bool(medico_ok) if medico_ok is not None else med_txt in ('APTO','HABILITADO','APROBADO','APTO CON RESTRICCIONES')
    med_cell = _std_mod_cell('✅' if med_ok else '❌', 'Apto' if med_ok else 'No apto', 'ok' if med_ok else 'bad')

    indu = estado_norm(row_get(row,'estado_capacitacion'))
    indu_ok = flujo_induccion_ok(row)
    indu_cell = _std_mod_cell('✅' if indu_ok else '➖', 'Inducido' if indu_ok else 'Pendiente', 'ok' if indu_ok else 'pendiente')

    indum = estado_norm(row_get(row,'estado_indumentaria'))
    indum_ok = flujo_indumentaria_ok(row)
    indum_cell = _std_mod_cell('✅' if indum_ok else '➖', 'Entregado' if indum_ok else 'Pendiente', 'ok' if indum_ok else 'pendiente')

    foto_estado = estado_norm(row_get(row,'fotocheck_estado'))
    foto_ok = foto_estado in ('ENTREGADO','IMPRESO','CARGO GENERADO','LISTO PARA IMPRIMIR','FOTO APROBADA','OK')
    foto_cell = _std_mod_cell('✅' if foto_ok else '➖', 'Emitido' if foto_ok else 'Pendiente', 'ok' if foto_ok else 'pendiente')

    firma_estado = estado_norm(row_get(row,'estado_documentos'))
    firma_ok = firma_estado in ('FIRMADO','COMPLETO','COMPLETADO','APROBADO','OK')
    firma_cell = _std_mod_cell('✅' if firma_ok else '🕘', 'Firmado' if firma_ok else 'Pendiente', 'ok' if firma_ok else 'pendiente')

    return f"""
      <tr data-dni='{dni}' data-estado='{h(estado)}'>
        <td class='std-sel'><input type='checkbox' name='{checkbox_name}' value='{rid}'></td>
        <td class='std-num'>{h(idx)}</td>
        <td><span class='std-avatar'>{foto_icon}</span></td>
        <td><b>{dni}</b></td>
        <td class='std-name'><b>{trabajador}</b></td>
        <td class='std-cargo'>{cargo}</td>
        <td><span class='std-pill {cls}'>{'Completo' if estado=='COMPLETO' else ('En validación' if pct else 'Incompleto')}</span></td>
        <td><b>{pct}%</b><div class='std-bar'><span style='width:{pct}%'></span></div></td>
        <td>{med_cell}</td>
        <td>{indu_cell}</td>
        <td>{indum_cell}</td>
        <td>{foto_cell}</td>
        <td>{firma_cell}</td>
        <td>{acciones_estandar_postulante(row, req=req, extra=extra_action)}</td>
      </tr>
    """


def tabla_estandar_postulantes_header(tabla_id):
    return f"""<tr><th class='std-sel'><input type='checkbox' onclick=\"document.querySelectorAll('#{tabla_id} input[name=ingreso_ids]').forEach(x=>x.checked=this.checked)\"></th><th>N°</th><th>Foto</th><th>DNI</th><th>Trabajador</th><th>Cargo</th><th>Estado proceso</th><th>% Completitud</th><th>Evaluación médica</th><th>Inducción</th><th>Indumentaria</th><th>Fotocheck</th><th>Firma contratos</th><th>Acciones</th></tr>"""


def fila_pp_postulante_estandar(row, req='', medico_ok=None, extra_action='', idx=''):
    """Fila idéntica al diseño premium del módulo Postulantes: N°, Foto, DNI, Trabajador,
    Cargo, Estado proceso, % Completitud, módulos y 4 acciones finales."""
    estado, pct, faltan = modulos_faltantes_postulante(row, medico_ok=medico_ok)
    cls = 'ok' if estado == 'COMPLETO' else ('warn' if pct else 'bad')
    dni = h(row_get(row, 'dni'))
    req_val = h(req or row_get(row, 'requerimiento'))
    trabajador = h(row_get(row, 'trabajador') or 'PENDIENTE COMPLETAR')
    cargo = h(row_get(row, 'cargo') or 'SIN CARGO')
    foto_icon = '📷' if clean(row_get(row,'foto_ruta')) else '👤'

    med_txt = estado_norm(row_get(row,'estado_medico') or row_get(row,'aptitud_medica'))
    med_ok = bool(medico_ok) if medico_ok is not None else med_txt in ('APTO','HABILITADO','APROBADO','APTO CON RESTRICCIONES')
    med_label = 'APTO' if med_ok else 'PENDIENTE'

    indu_ok = flujo_induccion_ok(row)
    indum_ok = flujo_indumentaria_ok(row)
    foto_estado = estado_norm(row_get(row,'fotocheck_estado'))
    foto_ok = foto_estado in ('ENTREGADO','IMPRESO','CARGO GENERADO','LISTO PARA IMPRIMIR','FOTO APROBADA','OK','EMITIDO')
