CAMPOS_FICHA_OBLIGATORIOS_PRO = [
    ('trabajador','Trabajador'),('dni','DNI'),('empresa','Empresa'),('area','Área'),('cargo','Cargo'),
    ('actividad','Actividad'),('fecha_ingreso','Fecha ingreso'),('fecha_nacimiento','Fecha nacimiento'),
    ('direccion','Dirección'),('distrito','Distrito'),('provincia','Provincia'),('departamento','Departamento'),
    ('remuneracion_basica','Remuneración básica'),('tipo_contrato','Tipo contrato'),('regimen_laboral','Régimen laboral')
]

def estado_norm(v):
    return clean(v).upper().replace('Á','A').replace('É','E').replace('Í','I').replace('Ó','O').replace('Ú','U')

def campos_faltantes_postulante(row):
    r = row_to_dict(row)
    faltan = []
    for campo, etiqueta in CAMPOS_FICHA_OBLIGATORIOS_PRO:
        if es_valor_incompleto(r.get(campo)):
            faltan.append(etiqueta)
    return faltan

def estado_ficha_postulante(row):
    faltan = campos_faltantes_postulante(row)
    if faltan:
        return 'FICHA INCOMPLETA'
    return 'LISTO PARA DOCUMENTOS'

def documentos_por_postulante(dni, requerimiento=''):
    with db() as con:
        docs = con.execute('SELECT * FROM contratacion_docs WHERE dni=? ORDER BY id DESC', (normalizar_dni(dni),)).fetchall()
        firmas = con.execute('SELECT * FROM firma_solicitudes WHERE dni=? ORDER BY id DESC', (normalizar_dni(dni),)).fetchall()
    generados = len(docs)
    enviados = sum(1 for x in docs if 'FIRMA' in estado_norm(row_get(x,'estado')))
    firmados = sum(1 for x in firmas if 'FIRMAD' in estado_norm(row_get(x,'estado')))
    return generados, enviados, firmados

def aptitud_medica_actual(dni, requerimiento=''):
    with db() as con:
        if requerimiento:
            r = con.execute('SELECT * FROM contratacion_medica WHERE dni=? AND requerimiento=? ORDER BY id DESC LIMIT 1', (normalizar_dni(dni), requerimiento)).fetchone()
        else:
            r = None
        if not r:
            r = con.execute('SELECT * FROM contratacion_medica WHERE dni=? ORDER BY id DESC LIMIT 1', (normalizar_dni(dni),)).fetchone()
    return estado_norm(row_get(r, 'estado', 'PENDIENTE'))

def puede_pasar_a_firma(dni, requerimiento=''):
    data = datos_unificados_contratacion(dni, requerimiento)
    faltan = []
    for campo, etiqueta in CAMPOS_FICHA_OBLIGATORIOS_PRO:
        if es_valor_incompleto(data.get(campo)):
            faltan.append(etiqueta)
    medico = aptitud_medica_actual(dni, requerimiento)
    if medico != 'APTO':
        faltan.append('Evaluación médica APTO')
    return (not faltan), faltan

def int_safe(v, default=0):
    """Convierte números de formularios/BD a entero de forma segura."""
    try:
        if v is None:
            return default
        txt = str(v).strip()
        if txt == '':
            return default
        return int(float(txt))
    except Exception:
        return default


def cantidad_solicitada_requerimiento(row):
    """Devuelve la cantidad solicitada real del requerimiento.
    Se centraliza para evitar que el sistema lea 1 por defecto o un campo equivocado.
    """
    if not row:
        return 0
    try:
        keys = row.keys()
    except Exception:
        keys = []
    for campo in ('cantidad', 'cantidad_solicitada', 'cupos_solicitados', 'total'):
        try:
            if campo in keys:
                n = int_safe(row[campo], 0)
                if n > 0:
                    return n
        except Exception:
            pass
    return 0


def contar_postulantes_requerimiento(con, requerimiento):
    """Cuenta solo postulantes activos vinculados exactamente al requerimiento/requerimiento."""
    requerimiento = clean(requerimiento)
    if not requerimiento:
        return 0
    return int(con.execute("""SELECT COUNT(*)
                              FROM contratacion_ingresos
                              WHERE TRIM(COALESCE(requerimiento,''))=TRIM(?)
                                AND UPPER(COALESCE(estado,'')) NOT IN ('ANULADO','CANCELADO')""", (requerimiento,)).fetchone()[0] or 0)


def sincronizar_estado_requerimiento_por_cupo(con, requerimiento):
    if not requerimiento:
        return
    req = con.execute('SELECT * FROM contratacion_requerimientos WHERE TRIM(requerimiento)=TRIM(?) ORDER BY id DESC LIMIT 1', (requerimiento,)).fetchone()
    if not req:
        return
    cantidad = cantidad_solicitada_requerimiento(req)
    registrados = contar_postulantes_requerimiento(con, requerimiento)
    completos = int(con.execute("""SELECT COUNT(*)
                                   FROM contratacion_ingresos
                                   WHERE TRIM(COALESCE(requerimiento,''))=TRIM(?)
                                     AND UPPER(COALESCE(estado,'')) NOT IN ('ANULADO','CANCELADO')
                                     AND UPPER(COALESCE(estado,'')) IN ('REGISTRADO','LISTO PARA DOCUMENTOS')""", (requerimiento,)).fetchone()[0] or 0)
    # Guarda los contadores en la tabla para que el dashboard y reportes siempre muestren lo mismo.
    try:
        con.execute("UPDATE contratacion_requerimientos SET cupos_registrados=?, cupos_completos=? WHERE TRIM(requerimiento)=TRIM(?)", (registrados, completos, requerimiento))
    except Exception:
        pass
    if cantidad > 0 and registrados >= cantidad:
        con.execute("UPDATE contratacion_requerimientos SET estado='CUPO CERRADO', observacion=COALESCE(observacion,'') || ' | Cupo cerrado automáticamente.' WHERE TRIM(requerimiento)=TRIM(?) AND estado NOT IN ('CERRADO')", (requerimiento,))
    elif registrados > 0:
        con.execute("UPDATE contratacion_requerimientos SET estado='EN REGISTRO' WHERE TRIM(requerimiento)=TRIM(?) AND estado NOT IN ('CERRADO','CUPO CERRADO')", (requerimiento,))
    elif registrados == 0:
        con.execute("UPDATE contratacion_requerimientos SET estado='SOLICITADO' WHERE TRIM(requerimiento)=TRIM(?) AND estado IN ('EN REGISTRO','CUPO CERRADO')", (requerimiento,))


def registrar_dni_en_requerimiento_backend(requerimiento, dni, usuario='admin'):
    """Registro único y real de DNI al requerimiento.
    Usado por digitación manual, lector USB/código de barras y cámara.
    """
    requerimiento = clean(requerimiento)
    dni = normalizar_dni(dni)
    if not requerimiento or not dni or len(dni) != 8:
        return {'ok': False, 'msg': 'Seleccione requerimiento y registre un DNI válido de 8 dígitos.', 'sound': 'error'}

    with db() as con:
        req = con.execute('SELECT * FROM contratacion_requerimientos WHERE TRIM(requerimiento)=TRIM(?) ORDER BY id DESC LIMIT 1', (requerimiento,)).fetchone()
        if not req:
            return {'ok': False, 'msg': f'No se encontró el requerimiento {requerimiento}. Vuelva a seleccionarlo.', 'sound': 'error'}

        cantidad_req = cantidad_solicitada_requerimiento(req)
        if cantidad_req <= 0:
            return {'ok': False, 'msg': f'El requerimiento {requerimiento} no tiene cantidad solicitada válida. Edite el requerimiento e ingrese la cantidad real.', 'sound': 'error'}

        # BLOQUEO PRO: un DNI activo solo puede estar en UN requerimiento.
        # Si fue digitado por error, primero debe anularse desde Requerimiento > Ver/Eliminar postulantes.
        existe = con.execute("""SELECT id FROM contratacion_ingresos
                              WHERE dni=? AND TRIM(COALESCE(requerimiento,''))=TRIM(?)
                                AND UPPER(COALESCE(estado,'')) NOT IN ('ANULADO','CANCELADO')
                              ORDER BY id DESC LIMIT 1""", (dni, requerimiento)).fetchone()
        if existe:
            registrados_req = contar_postulantes_requerimiento(con, requerimiento)
            return {'ok': False, 'msg': f'ALERTA: el DNI {dni} ya está registrado activo en el requerimiento {requerimiento}. No se permite duplicar postulante.',
                    'sound': 'error', 'registrados': registrados_req, 'cantidad': cantidad_req}

        existe_otro = con.execute("""SELECT id, requerimiento, estado FROM contratacion_ingresos
                                    WHERE dni=?
                                      AND TRIM(COALESCE(requerimiento,''))<>TRIM(?)
                                      AND UPPER(COALESCE(estado,'')) NOT IN ('ANULADO','CANCELADO')
                                    ORDER BY id DESC LIMIT 1""", (dni, requerimiento)).fetchone()
        if existe_otro:
            req_otro = clean(row_get(existe_otro, 'requerimiento'))
            return {'ok': False,
                    'msg': f'BLOQUEADO: el DNI {dni} ya está activo en el requerimiento {req_otro}. Para moverlo a {requerimiento}, primero anúlelo/elímínelo desde Ver/Eliminar postulantes del requerimiento anterior.',
                    'sound': 'error',
                    'duplicado_otro_requerimiento': True,
                    'requerimiento_actual': req_otro,
                    'requerimiento': requerimiento,
                    'registrados': contar_postulantes_requerimiento(con, requerimiento),
                    'cantidad': cantidad_req}

        registrados_req = contar_postulantes_requerimiento(con, requerimiento)
        if registrados_req >= cantidad_req:
            con.execute("UPDATE contratacion_requerimientos SET estado='CUPO CERRADO', cupos_registrados=? WHERE TRIM(requerimiento)=TRIM(?)", (registrados_req, requerimiento))
            con.commit()
            return {'ok': False, 'msg': f'CUPO COMPLETO: el requerimiento {requerimiento} solicitó {cantidad_req} postulante(s) y ya tiene {registrados_req}. No se puede registrar más personal.',
                    'sound': 'error', 'cupo': True, 'registrados': registrados_req, 'cantidad': cantidad_req}

        trab = con.execute('SELECT * FROM trabajadores WHERE dni=?', (dni,)).fetchone()
        if trab and clean(trab['nombre']):
            nombre = trab['nombre'] or ''
            tipo = 'REINGRESANTE'
            empresa = trab['empresa'] or req['empresa'] or 'AQUANQA'
            cargo = trab['cargo'] or req['cargo'] or ''
            area = trab['area'] or req['area'] or ''
            correo = trab['correo'] or ''
            celular = trab['celular'] or ''
        else:
            nombre = ''
            tipo = 'NUEVO'
            empresa = req['empresa'] or 'AQUANQA'
            cargo = req['cargo'] or ''
            area = req['area'] or ''
            correo = ''
            celular = ''
            con.execute("""INSERT OR IGNORE INTO trabajadores
                           (dni,nombre,empresa,activo,fecha_registro,usuario_portal,clave_portal)
                           VALUES(?,?,?,1,?,?,?)""", (dni, '', empresa, now_txt(), dni, dni))

        fecha_inicio_req = row_get(req, 'fecha_inicio_contrato') or row_get(req, 'fecha_ingreso') or fecha_sin_hora(hoy_iso())
        fecha_fin_req = row_get(req, 'fecha_fin_contrato') or ''
        tipo_contrato_req = row_get(req, 'tipo_contrato') or ''
        regimen_req = row_get(req, 'regimen_laboral') or ''
        vals = (
            dni, nombre, empresa, req['sede'] or '', requerimiento, req['actividad'] or '', tipo,
            'PRE REGISTRADO', fecha_inicio_req,
            cargo, area, correo, celular,
            'Registrado automáticamente desde digitación/lector/cámara en requerimiento',
            now_txt(), usuario or 'admin', fecha_inicio_req, fecha_fin_req, tipo_contrato_req, regimen_req
        )
        con.execute("""INSERT INTO contratacion_ingresos
            (dni,trabajador,empresa,sede,requerimiento,actividad,tipo_ingreso,estado,fecha_ingreso,cargo,area,correo,celular,observacion,fecha_registro,registrado_por,fecha_inicio_contrato,fecha_fin_contrato,tipo_contrato,regimen_laboral)
            VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""", vals)
        sincronizar_estado_requerimiento_por_cupo(con, requerimiento)
        # Recalcula estado por cupo inmediatamente para que aparezca CUPO CERRADO al llegar al total solicitado.
        registrados_final = contar_postulantes_requerimiento(con, requerimiento)
        sincronizar_estado_requerimiento_por_cupo(con, requerimiento)
        con.commit()

    return {
        'ok': True,
        'msg': f'POSTULANTE REGISTRADO: DNI {dni} vinculado al requerimiento {requerimiento}.',
        'sound': 'ok',
        'dni': dni,
        'tipo': tipo,
        'nombre': nombre or '',
        'requerimiento': requerimiento,
        'registrados': registrados_final,
        'cantidad': cantidad_req
    }


def semaforo_clase_estado(valor):
    v = estado_norm(valor)
    if any(x in v for x in ['APTO','LISTO','FIRMADO','COMPLETO','APROBADO','ENTREGADO']):
        return 'ok'
    if any(x in v for x in ['NO APTO','OBSERVADO','INCOMPLETO','PENDIENTE','BLOQUEADO']):
        return 'warn'
    return 'info'

def separar_nombres_apellidos(nombre):
    txt = clean(nombre)
    if ',' in txt:
        ap, nom = [x.strip() for x in txt.split(',', 1)]
        aps = ap.split()
        return (aps[0] if aps else '', ' '.join(aps[1:]) if len(aps) > 1 else '', nom)
    partes = txt.split()
    if len(partes) >= 3:
        return partes[0], partes[1], ' '.join(partes[2:])
    return '', '', txt


def formato_fecha_texto(fecha, mayus=False):
    d = parse_fecha_any(fecha)
    if not d:
        return fecha_sin_hora(fecha)
    meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre']
    txt = f"{d.day:02d} de {meses[d.month-1]} de {d.year}"
    return txt.upper() if mayus else txt


def valores_esquema_desde_trabajador(trabajador=None):
    t = trabajador or {}
    nombre = clean(row_get(t, 'nombre') or row_get(t, 'trabajador'))
    ap_pat, ap_mat, nombres = separar_nombres_apellidos(nombre)
    fecha_ing = row_get(t, 'fecha_ingreso'); fecha_fin = row_get(t, 'fecha_fin_contrato'); fecha_nac = row_get(t, 'fecha_nacimiento')
    empresa = row_get(t, 'empresa'); cargo = row_get(t, 'cargo') or row_get(t, 'puesto'); area = row_get(t, 'area')
    correo = row_get(t, 'correo') or row_get(t, 'email'); planilla = row_get(t, 'planilla'); dni = row_get(t, 'dni')
    direccion = row_get(t, 'direccion') or row_get(t, 'direccion_actual'); departamento=row_get(t,'departamento'); provincia=row_get(t,'provincia'); distrito=row_get(t,'distrito')
    remuneracion = row_get(t, 'remuneracion_basica') or row_get(t, 'basico'); celular = row_get(t, 'celular') or row_get(t, 'telefono')
    estado_civil=row_get(t,'estado_civil'); sistema_pensionario=row_get(t,'sistema_pensionario'); actividad=row_get(t,'actividad'); sede=row_get(t,'sede')
    nacionalidad = row_get(t, 'nacionalidad') or 'PERUANA'
    sexo = row_get(t, 'sexo')
    regimen_laboral = row_get(t, 'regimen_laboral') or row_get(t, 'planilla')
    periodicidad_pago = row_get(t, 'periodicidad_pago')
    tipo_pago = row_get(t, 'tipo_pago')
    cuspp = row_get(t, 'cuspp')
    nombre_moneda = row_get(t, 'nombre_moneda') or 'Sol Peruano'
    simbolo_moneda = row_get(t, 'simbolo_moneda') or 'S/'
    funciones = row_get(t, 'funciones')
    meses_contrato = row_get(t, 'meses_contrato')
    remuneracion_letra = row_get(t, 'remuneracion_letra')
    tipo_contrato = row_get(t, 'tipo_contrato') or row_get(t, 'modalidad')
    base = {
        'Dni': dni, 'NombreCompletoTrabajador': nombre, 'Email': correo, 'Cargo': cargo, 'Puesto': cargo, 'Ocupacion': cargo,
        'Area': area, 'Gerencia': area, 'Planilla': planilla, 'TipoContrato': tipo_contrato, 'Actividad': actividad, 'Zona': sede or actividad, 'Sede': sede,
        'DireccionActual': direccion, 'DireccionDNI': direccion, 'Departamento': departamento, 'Provincia': provincia, 'Distrito': distrito, 'NroTelefonoMovil': celular,
        'FechaIniContrato': fecha_sin_hora(fecha_ing), 'FechaInicioContrato': fecha_sin_hora(fecha_ing), 'FechaInicioContratoOrigen': fecha_sin_hora(fecha_ing),
        'FechaIniContratoBarra': fecha_sin_hora(fecha_ing), 'FechaIniContratoGuion': fecha_sin_hora(fecha_ing).replace('/','-'), 'FechaIniContratoISO': fecha_iso_segura(fecha_ing),
        'FechaIniContratoTextoMayuscula': formato_fecha_texto(fecha_ing, True), 'FechaIniContratoTextoMinuscula': formato_fecha_texto(fecha_ing, False),
        'FechaFinContrato': fecha_sin_hora(fecha_fin), 'FechaFinContratoOrigen': fecha_sin_hora(fecha_fin), 'FechaFinContratoBarra': fecha_sin_hora(fecha_fin),
        'FechaFinContratoGuion': fecha_sin_hora(fecha_fin).replace('/','-'), 'FechaFinContratoISO': fecha_iso_segura(fecha_fin), 'FechaFinContratoTextoMayuscula': formato_fecha_texto(fecha_fin, True), 'FechaFinContratoTextoMinuscula': formato_fecha_texto(fecha_fin, False),
        'FechaNacimientoISO': fecha_iso_segura(fecha_nac), 'FechaNacimientoGuion': fecha_sin_hora(fecha_nac).replace('/','-'), 'FechaNacimientoBarra': fecha_sin_hora(fecha_nac),
        'FechaNacimientoTextoMayuscula': formato_fecha_texto(fecha_nac, True), 'FechaNacimientoTextoMinuscula': formato_fecha_texto(fecha_nac, False),
        'ApellidoPaternoTrabajador': ap_pat, 'ApellidoMaternoTrabajador': ap_mat, 'NombreTrabajador': nombres, 'Estado': 'Activo', 'Condicion': 'ACTIVO' if row_get(t, 'activo', 1) else 'INACTIVO',
        'CentroCosto': empresa, 'NombreMoneda': nombre_moneda, 'SimboloMoneda': simbolo_moneda, 'NombreTipoDocumentoIdentidad': 'DOC. NACIONAL DE IDENTIDAD', 'NombreCortoTipoDocumentoIdentidad': 'DNI',
        'RemunBasica': remuneracion, 'RemuneracionBasica': remuneracion, 'RemunBasicaAgraria': remuneracion, 'RemuneracionLetra': remuneracion_letra,
        'EstadoCivil': estado_civil, 'SistemaPensionario': sistema_pensionario, 'Nacionalidad': nacionalidad, 'Sexo': sexo,
        'RegimenLaboral': regimen_laboral, 'PeriodicidadPago': periodicidad_pago, 'TipoPago': tipo_pago, 'Cuspp': cuspp,
        'Funciones': funciones, 'MesesContrato': meses_contrato, 'NumeroMesesContrato': meses_contrato, 'DuracionContratoTexto': row_get(t, 'duracion_contrato_texto') or meses_contrato
    }
    salida=[]
    for campo, ejemplo in CAMPOS_ESQUEMA_TRABAJADOR_CONTRATO_LABORAL:
        salida.append((campo, clean(base.get(campo))))
    for campo, valor in base.items():
        if not any(c == campo for c, v in salida): salida.append((campo, clean(valor)))
    return salida


def mapa_campos_trabajador(trabajador=None):
    """Diccionario CampoOrigen -> valor real del trabajador para combinar correspondencia.
    PRO: no usa datos de ejemplo. Si un campo no existe en BD queda vacío para validar antes de enviar.
    """
    return {campo: valor for campo, valor in valores_esquema_desde_trabajador(trabajador)}


def es_valor_incompleto(v):
    txt = clean(v).strip()
    if not txt:
        return True
    basura = {'0001-01-01','01/01/0001','01-01-0001','NONE','NULL','N/A','NA','SIN DATO','SIN DATOS','PENDIENTE'}
    return txt.upper() in basura


def campos_usados_en_plantilla(pl=None, campos_registrados=None):
    """Devuelve los campos Word realmente usados por la plantilla.
    Prioriza lo detectado dentro del .docx; si no puede leerlo, usa los campos activos registrados.
    """
    usados = []
    try:
        ruta = Path(pl['ruta_archivo']) if pl and pl['ruta_archivo'] else None
        if ruta and ruta.exists() and ruta.suffix.lower() == '.docx':
            usados = extraer_campos_word_docx(ruta)
    except Exception:
        usados = []
    if not usados and campos_registrados:
        for c in campos_registrados:
            try:
                if int(c['activo'] or 0) and clean(c['requerido'] or 'SI').upper() == 'SI':
                    usados.append(clean(c['campo_origen'] or c['nombre_campo']))
            except Exception:
                usados.append(clean(c['campo_origen'] or c['nombre_campo']))
    # Campos técnicos/no críticos que no deben bloquear el envío si no están en BD.
    no_bloquea = {'Comentario','SituacionEspecial','Cuspp','Indeterminado'}
    salida=[]
    for x in usados:
        x=clean(x)
        if x and x not in salida and x not in no_bloquea:
            salida.append(x)
    return salida


def validar_datos_plantilla(pid, dni=''):
    """Valida si el trabajador tiene todos los datos que pide el Word.
    Retorna dict con ok, faltantes, valores, trabajador, plantilla.
    """
    dni = normalizar_dni(dni)
    with db() as con:
        pl = con.execute('SELECT * FROM contratacion_plantillas WHERE id=?', (pid,)).fetchone()
        campos = con.execute('SELECT * FROM contratacion_plantilla_campos WHERE plantilla_id=? AND activo=1 ORDER BY id', (pid,)).fetchall() if pl else []
        trabajador = datos_unificados_contratacion(dni) if dni else None
    if not pl:
        return {'ok': False, 'error':'Plantilla no encontrada', 'faltantes':['Plantilla'], 'valores':{}, 'trabajador':None, 'plantilla':None, 'campos_usados':[]}
    if not trabajador or es_valor_incompleto(trabajador.get('nombre')):
        return {'ok': False, 'error':'Trabajador no encontrado o sin ficha completa', 'faltantes':['Trabajador/DNI'], 'valores':{}, 'trabajador':None, 'plantilla':pl, 'campos_usados':[]}
    valores = mapa_campos_trabajador(trabajador)
    usados = campos_usados_en_plantilla(pl, campos)
    # Compatibilidad con nombres antiguos/similares.
    equivalencias = {
        'FechaInicioContrato':'FechaIniContrato', 'FechaFinContratoOrigen':'FechaFinContrato',
        'RemuneracionBasica':'RemunBasica', 'Remuneración Básica':'RemunBasica',
        'Telefono':'NroTelefonoMovil', 'Celular':'NroTelefonoMovil',
    }
    faltantes=[]
    for campo in usados:
        key = equivalencias.get(campo, campo)
        valor = valores.get(key, valores.get(campo, ''))
        if es_valor_incompleto(valor):
            faltantes.append(campo)
    return {'ok': len(faltantes)==0, 'error':'', 'faltantes':faltantes, 'valores':valores, 'trabajador':trabajador, 'plantilla':pl, 'campos_usados':usados}


def resumen_validacion_html(resultado):
    faltantes = resultado.get('faltantes') or []
    if not faltantes:
        return "<span class='cond-ok'>✅ Datos completos. Documento habilitado para generar/enviar.</span>"
    lis = ''.join(f"<li><code>{html.escape(x)}</code></li>" for x in faltantes)
    return f"<div class='missing-box'><b>⚠ Faltan datos obligatorios. No se debe enviar el documento.</b><ul>{lis}</ul><small>Completa la ficha del trabajador/base Excel y vuelve a previsualizar.</small></div>"


def evaluar_condicion_valor(actual, operador, esperado):
    """Evalúa condiciones de plantilla contra los datos del trabajador."""
    actual_txt = clean(actual).upper()
    esperado_txt = clean(esperado).upper()
    op = clean(operador).upper() or '='
    if op in ('=', '=='):
        return actual_txt == esperado_txt
    if op in ('<>', '!='):
        return actual_txt != esperado_txt
    if op == 'CONTIENE':
        return esperado_txt in actual_txt
    if op == 'NO CONTIENE':
        return esperado_txt not in actual_txt
    try:
        a = float(re.sub(r'[^0-9.-]', '', actual_txt) or 0)
        b = float(re.sub(r'[^0-9.-]', '', esperado_txt) or 0)
        if op == '>': return a > b
        if op == '<': return a < b
        if op == '>=': return a >= b
        if op == '<=': return a <= b
    except Exception:
        return False
    return False


def plantilla_cumple_condiciones(plantilla, condiciones, trabajador=None):
    """Retorna (cumple, detalle_html). Si la plantilla está SIN CONDICIONES, siempre cumple."""
    if not plantilla or (plantilla['condicion'] or '').upper() != 'CONDICIONES':
        return True, '<span class="cond-ok">Plantilla general: sin condiciones.</span>'
    valores = mapa_campos_trabajador(trabajador)
    if not condiciones:
        return False, '<span class="cond-bad">La plantilla exige condiciones, pero no tiene reglas registradas.</span>'
    partes = []
    cumple_todo = True
    for c in condiciones:
        if not int(c['activo'] or 0):
            continue
        campo_label = clean(c['nombre_campo'])
        campo_origen = None
        for nom, origen, td in CONTRATACION_CAMPOS_CORRESPONDENCIA:
            if nom == campo_label or origen == campo_label:
                campo_origen = origen
                break
        campo_origen = campo_origen or campo_label.replace(' ', '')
        actual = valores.get(campo_origen, '')
        ok = evaluar_condicion_valor(actual, c['condicion'], c['valor'])
        cumple_todo = cumple_todo and ok
        partes.append(f"<span class='{'cond-ok' if ok else 'cond-bad'}'>{html.escape(campo_label)} {html.escape(c['condicion'] or '=')} {html.escape(c['valor'] or '')} → dato trabajador: {html.escape(actual or 'VACÍO')}</span>")
    return cumple_todo, ' '.join(partes) if partes else '<span class="cond-bad">No hay condiciones activas.</span>'



def extraer_campos_word_docx(path):
    """Detecta campos de correspondencia escritos como «Campo» y {{Campo}} en un Word .docx."""
    campos = []
    if Document is None:
        return campos
    try:
        doc = Document(str(path))
    except Exception:
        return campos
    textos = []
    def add(txt):
        if txt:
            textos.append(str(txt))
    for p in doc.paragraphs:
        add(p.text)
    for table in doc.tables:
        for row in table.rows:
            for cell in row.cells:
                for p in cell.paragraphs:
                    add(p.text)
    texto = "\n".join(textos)
    # Soporta campos Word tipo combinación: «NombreCompletoTrabajador»
    # y campos internos del sistema: {{NombreCompletoTrabajador}}
    patrones = [r'«\s*([^»\n\r]+?)\s*»', r'\{\{\s*([^}\n\r]+?)\s*\}\}']
    vistos = set()
    for pat in patrones:
        for m in re.finditer(pat, texto):
            campo = clean(m.group(1)).strip()
            campo = re.sub(r'\s+', '', campo)
            if campo and campo not in vistos:
                vistos.add(campo); campos.append(campo)
    return campos


def sincronizar_campos_desde_word(plantilla_id, ruta_archivo):
    """Carga automáticamente a la pestaña Campos los campos encontrados en Word."""
    if not ruta_archivo:
        return 0
    path = Path(ruta_archivo)
    if not path.exists() or path.suffix.lower() != '.docx':
        return 0
    encontrados = extraer_campos_word_docx(path)
    if not encontrados:
        return 0
    tipos = {origen: td for nom, origen, td in CONTRATACION_CAMPOS_CORRESPONDENCIA}
    nombres = {origen: nom for nom, origen, td in CONTRATACION_CAMPOS_CORRESPONDENCIA}
    n = 0
    with db() as con:
        for campo in encontrados:
            existe = con.execute('SELECT 1 FROM contratacion_plantilla_campos WHERE plantilla_id=? AND campo_origen=?', (plantilla_id, campo)).fetchone()
            if not existe:
                con.execute("INSERT INTO contratacion_plantilla_campos(plantilla_id,descripcion,tipo_campo,nombre_campo,campo_origen,tipo_dato,requerido,activo) VALUES(?,?,?,?,?,?,?,1)",
                            (plantilla_id, 'Detectado automáticamente desde Word', 'Origen de Datos', nombres.get(campo, nombre_legible_campo(campo)), campo, tipos.get(campo, tipo_dato_esquema(campo)), 'SI'))
                n += 1
        con.commit()
    return n


def sincronizar_campos_desde_word_seguro(plantilla_id, ruta_archivo):
    """Versión segura para carga de plantillas: registra campos si puede, pero no genera Internal Server Error."""
    try:
        return sincronizar_campos_desde_word(plantilla_id, ruta_archivo)
    except Exception as e:
        print('Error detectando campos de Word:', e)
        return 0

def reemplazar_texto_docx(doc, valores):
    """Reemplaza campos {{CampoOrigen}} y «CampoOrigen» en párrafos y tablas de un Word."""
    def repl(txt):
        if not txt:
            return txt
        for k, v in valores.items():
            val = clean(v)
            txt = txt.replace('{{' + k + '}}', val)
            txt = txt.replace('{{ ' + k + ' }}', val)
            txt = txt.replace('«' + k + '»', val)
            txt = txt.replace('« ' + k + ' »', val)
        return txt
    def proc_paragraph(p):
        full = ''.join(run.text for run in p.runs)
        new = repl(full)
        if new != full:
            for run in p.runs:
                run.text = ''
            if p.runs:
                p.runs[0].text = new
            else:
                p.add_run(new)
    for p in doc.paragraphs:
        proc_paragraph(p)
    for table in doc.tables:
        for row in table.rows:
            for cell in row.cells:
                for p in cell.paragraphs:
                    proc_paragraph(p)
    return doc


def reemplazar_texto_docx_validado(doc, valores, faltantes=None):
    """Reemplaza campos y marca en amarillo los campos faltantes dentro del Word exportado."""
    try:
        from docx.enum.text import WD_COLOR_INDEX
    except Exception:
        WD_COLOR_INDEX = None
    faltantes = set(faltantes or [])
    patron = re.compile(r'(«\s*([^»\n\r]+?)\s*»|\{\{\s*([^}\n\r]+?)\s*\}\})')
    equivalencias = {'FechaInicioContrato':'FechaIniContrato', 'RemuneracionBasica':'RemunBasica'}

    def partes(txt):
        pos = 0
        for m in patron.finditer(txt or ''):
            if m.start() > pos:
                yield ('texto', txt[pos:m.start()], None)
            campo = clean(m.group(2) or m.group(3)).replace(' ', '')
            key = equivalencias.get(campo, campo)
            val = clean(valores.get(key, valores.get(campo, '')))
            if campo in faltantes or key in faltantes or es_valor_incompleto(val):
                yield ('faltante', f'«{campo}»', campo)
            else:
                yield ('valor', val, campo)
            pos = m.end()
        if pos < len(txt or ''):
            yield ('texto', txt[pos:], None)

    def proc_paragraph(p):
        full = ''.join(run.text for run in p.runs)
        if not patron.search(full or ''):
            return
        for run in p.runs:
            run.text = ''
        first = True
        for tipo, texto, campo in partes(full):
            r = p.runs[0] if first and p.runs else p.add_run()
            first = False
            r.text = texto
            if tipo == 'faltante':
                r.bold = True
                if WD_COLOR_INDEX:
                    r.font.highlight_color = WD_COLOR_INDEX.YELLOW
    for p in doc.paragraphs:
        proc_paragraph(p)
    for table in doc.tables:
        for row in table.rows:
            for cell in row.cells:
                for p in cell.paragraphs:
                    proc_paragraph(p)
    return doc


def reemplazar_campos_html(texto, valores, faltantes=None):
    faltantes=set(faltantes or [])
    equivalencias={'FechaInicioContrato':'FechaIniContrato','RemuneracionBasica':'RemunBasica'}
    def repl(m):
        campo=clean(m.group(1) or m.group(2)).replace(' ','')
        key=equivalencias.get(campo,campo)
        val=clean(valores.get(key, valores.get(campo,'')))
        if campo in faltantes or key in faltantes or es_valor_incompleto(val):
            return f"<mark class='miss-field'>«{html.escape(campo)}»</mark>"
        return html.escape(val)
    return re.sub(r'«\s*([^»\n\r]+?)\s*»|\{\{\s*([^}\n\r]+?)\s*\}\}', repl, texto or '')


def generar_docx_desde_plantilla(pid, dni=''):
    """Genera un DOCX combinado. Si faltan datos, exporta el Word con campos faltantes marcados en amarillo."""
    if Document is None:
        raise RuntimeError('python-docx no está instalado.')
    dni = normalizar_dni(dni)
    resultado = validar_datos_plantilla(pid, dni)
    pl = resultado.get('plantilla')
    trabajador = resultado.get('trabajador')
    if not pl:
        raise FileNotFoundError('Plantilla no encontrada.')
    valores = resultado.get('valores') or {}
    faltantes = resultado.get('faltantes') or []
    with db() as con:
        campos = con.execute('SELECT * FROM contratacion_plantilla_campos WHERE plantilla_id=? AND activo=1 ORDER BY id', (pid,)).fetchall()
        condiciones = con.execute('SELECT * FROM contratacion_plantilla_condiciones WHERE plantilla_id=? ORDER BY id', (pid,)).fetchall()
    # Asegura que todos los campos registrados existan, aunque no haya dato en trabajador.
    for c in campos:
        key = c['campo_origen'] or c['nombre_campo']
        try:
            tipo_campo = (c['tipo_campo'] or '').upper()
            valor_default = c['valor_default'] if 'valor_default' in c.keys() else ''
        except Exception:
            tipo_campo, valor_default = '', ''
        if tipo_campo in ('MANUAL','DESPLEGABLE') and valor_default and key not in faltantes:
            valores[key] = valor_default
        else:
            valores.setdefault(key, '')
    cumple, detalle = plantilla_cumple_condiciones(pl, condiciones, trabajador)
    ruta = Path(pl['ruta_archivo']) if pl['ruta_archivo'] else None
    if ruta and ruta.exists() and ruta.suffix.lower() == '.docx':
        doc = Document(str(ruta))
    else:
        doc = Document()
        doc.add_heading(pl['nombre_plantilla'] or 'Documento contractual', level=1)
        doc.add_paragraph('Plantilla generada automáticamente. Reemplace el contenido por su Word oficial o use los campos siguientes:')
        doc.add_paragraph('Trabajador: {{NombreCompletoTrabajador}}')
        doc.add_paragraph('DNI: {{Dni}}')
        doc.add_paragraph('Cargo: {{Cargo}}')
        doc.add_paragraph('Planilla: {{Planilla}}')
        doc.add_paragraph('Tipo Contrato: {{TipoContrato}}')
    reemplazar_texto_docx_validado(doc, valores, faltantes)
    if faltantes:
        doc.add_page_break()
        doc.add_heading('OBSERVACIÓN DE DATOS INCOMPLETOS', level=1)
        doc.add_paragraph('Este documento NO debe enviarse a firma hasta completar la información marcada en amarillo.')
        for x in faltantes:
            doc.add_paragraph(f'Falta completar: {x}', style=None)
    safe_name = re.sub(r'[^A-Za-z0-9_ -]+', '', pl['nombre_plantilla'] or 'plantilla').strip() or 'plantilla'
    out_dir = UPLOAD_DIR / 'contratacion' / 'generados'
    out_dir.mkdir(parents=True, exist_ok=True)
    estado = 'OBSERVADO_DATOS_INCOMPLETOS' if faltantes else 'VALIDADO'
    out = out_dir / f"{safe_name}_{dni or 'SIN_DNI'}_{estado}_{now_file()}.docx"
    doc.save(out)
    return out, pl, trabajador, (cumple and not faltantes), detalle, faltantes


def docx_to_preview_html(path, valores=None, faltantes=None):
    """Vista previa simple de Word en HTML. Marca en amarillo los campos faltantes."""
    if Document is None:
        return '<div class="preview-empty"><b>No se puede previsualizar Word porque falta python-docx.</b><br>En Render usa <b>Clear build cache & deploy</b>; en local ejecuta <code>pip install -r requirements.txt</code>.</div>'
    try:
        doc = Document(str(path))
    except Exception as e:
        return f'<div class="preview-empty"><b>Plantilla Word cargada correctamente, pero no se pudo generar la vista previa.</b><br>Archivo: {html.escape(Path(path).name)}<br>Detalle técnico: {html.escape(str(e))}<br><br><a class="c-btn gray" href="javascript:history.back()">Volver</a></div>'
    valores = valores or {}
    faltantes = faltantes or []
    parts = ["<div class='word-preview'>"]
    for p in doc.paragraphs:
        txt = reemplazar_campos_html(p.text or '', valores, faltantes).replace('\n','<br>')
        if txt.strip():
            parts.append(f"<p>{txt}</p>")
    for table in doc.tables:
        parts.append("<table class='word-table'>")
        for row in table.rows:
            cells=[]
            for cell in row.cells:
                cell_txt = reemplazar_campos_html(cell.text or '', valores, faltantes).replace(chr(10), '<br>')
                cells.append(f"<td>{cell_txt}</td>")
            parts.append('<tr>' + ''.join(cells) + '</tr>')
        parts.append('</table>')
    parts.append('</div>')
    return ''.join(parts)


def generar_clave_trabajador(dni, fecha_nac=''):
    """Clave del trabajador: fecha de nacimiento sin / ni guiones (ddmmaaaa)."""
    if hasattr(fecha_nac, 'strftime'):
        return fecha_nac.strftime('%d%m%Y')
    txt = str(fecha_nac or '').strip()
    nums = re.sub(r"\D", "", txt)
    if len(nums) >= 8:
        return nums[:8]
    dni = normalizar_dni(dni)
    return (dni[-4:] + "PRIZE").upper()


def registrar_evento_documento(doc_id, dni, evento, detalle=''):
    with db() as con:
        con.execute("INSERT INTO eventos_documento(documento_id,dni,evento,fecha,detalle) VALUES(?,?,?,?,?)", (doc_id, normalizar_dni(dni), evento, now_txt(), clean(detalle)))
        if evento in ['Abierto','Leído','Recibido']:
            con.execute("UPDATE documentos SET fecha_lectura=?, leido_por=? WHERE id=? AND (fecha_lectura IS NULL OR fecha_lectura='')", (now_txt(), normalizar_dni(dni), doc_id))
        con.commit()


def listar_documentos(dni=None, tipo=None, categoria=None, periodo=None, buscar=None, limit=300):
    where, params = [], []
    if dni:
        where.append("(dni=? OR categoria='empresa')")
        params.append(normalizar_dni(dni))
    if tipo:
        where.append("tipo=?")
        params.append(tipo)
    if categoria:
        where.append("categoria=?")
        params.append(categoria)
    if periodo:
        where.append("periodo=?")
        params.append(periodo)
    if buscar:
        b = f"%{buscar}%"
        where.append("(dni LIKE ? OR tipo LIKE ? OR periodo LIKE ? OR detalle LIKE ? OR observacion LIKE ? OR archivo_nombre LIKE ?)")
        params += [b, b, b, b, b, b]
    sql = "SELECT * FROM documentos"
    if where:
        sql += " WHERE " + " AND ".join(where)
    sql += " ORDER BY id DESC LIMIT ?"
    params.append(limit)
    with db() as con:
        return con.execute(sql, params).fetchall()


def periodos_disponibles(dni=None, tipo=None, categoria=None):
    where, params = ["periodo IS NOT NULL", "periodo<>''"], []
    if dni:
        where.append("(dni=? OR categoria='empresa')"); params.append(normalizar_dni(dni))
    if tipo:
        where.append("tipo=?"); params.append(tipo)
    if categoria:
        where.append("categoria=?"); params.append(categoria)
    sql = "SELECT DISTINCT periodo FROM documentos WHERE " + " AND ".join(where) + " ORDER BY periodo DESC LIMIT 80"
    with db() as con:
        return [r[0] for r in con.execute(sql, params).fetchall() if r[0]]


def parse_fecha_any(v):
    txt = clean(v)
    if not txt:
        return None
    if isinstance(v, datetime):
        return v.date()
    for fmt in ["%d/%m/%Y", "%Y-%m-%d", "%d-%m-%Y", "%Y/%m/%d"]:
        try:
            return datetime.strptime(txt.split()[0], fmt).date()
        except Exception:
            pass
    return None

def hoy_lima():
    """Fecha actual en Perú para validar vacaciones sin depender del navegador."""
    return datetime.now(APP_TZ).date()

def fecha_iso_segura(v):
    d = parse_fecha_any(v)
    return d.isoformat() if d else ''

def periodos_desde_ingreso(dni=None, tipo=None, max_meses=72):
    """Devuelve periodos desde la fecha de ingreso del trabajador hasta hoy."""
    inicio = None
    if dni:
        t = get_trabajador(dni)
        if t and 'fecha_ingreso' in t.keys():
            inicio = parse_fecha_any(t['fecha_ingreso'])
    hoy = datetime.now(APP_TZ).date()
    if not inicio:
        inicio = hoy.replace(day=1)
    inicio = inicio.replace(day=1)
    out=[]; y=inicio.year; m=inicio.month
    while (y < hoy.year or (y == hoy.year and m <= hoy.month)) and len(out) < max_meses:
        out.append(f"{y:04d}-{m:02d}")
        m += 1
        if m == 13:
            y += 1; m = 1
    docs = periodos_disponibles(dni=dni, tipo=tipo)
    return sorted(set(out + docs), reverse=True)


def guardar_documento(file_storage, dni, tipo, periodo, detalle="", observacion="", uploaded_by="sistema"):
    if not file_storage or not file_storage.filename:
        return None
    original = secure_filename(file_storage.filename)
    ext = Path(original).suffix.lower()
    if ext not in EXT_ALLOWED:
        raise ValueError(f"Extensión no permitida: {ext}")
    tipo_info = ALL_TIPOS.get(tipo, (tipo, "📄", "personal"))
    categoria = tipo_info[2]
    dni = normalizar_dni(dni) if categoria != "empresa" else ""
    periodo = safe_periodo(periodo)
    folder = UPLOAD_DIR / categoria / re.sub(r"[^A-Za-z0-9_\-]", "_", tipo) / periodo
    if dni:
        folder = folder / dni
    folder.mkdir(parents=True, exist_ok=True)
    tipo_file = re.sub(r"[^A-Za-z0-9_\-]+", "_", tipo)
    prefijo_dni = f"{dni}_" if dni else ""
    final = f"{prefijo_dni}{tipo_file}_{periodo}_{now_file()}_{original}"
    path = folder / final
    file_storage.save(path)
    # Copia automática a carpeta documental organizada para respaldo físico.
    try:
        label_auto, icon_auto, cat_auto = ALL_TIPOS.get(tipo, (tipo, '📄', categoria))
        root_name = {'pago':'DOCUMENTOS DE PAGO','empresa':'DOCUMENTOS DE LA EMPRESA','personal':'DOCUMENTOS PERSONALES'}.get(cat_auto,'DOCUMENTOS')
        auto_base = DOCUMENTOS_BASE_DIR / root_name / slug_folder(label_auto)
        if tipo == 'Normal' and 'seman' in clean(detalle).lower():
            auto_base = auto_base / 'SEMANAL'
        elif tipo == 'Normal':
            auto_base = auto_base / 'MENSUAL'
        auto_base = auto_base / periodo
        if dni: auto_base = auto_base / dni
        auto_base.mkdir(parents=True, exist_ok=True)
        auto_path = auto_base / final
        if str(auto_path) != str(path):
            auto_path.write_bytes(path.read_bytes())
    except Exception:
        pass
    with db() as con:
        con.execute("""
        INSERT INTO documentos(dni,categoria,tipo,periodo,detalle,observacion,archivo_nombre,ruta_archivo,extension,fecha_subida,uploaded_by)
        VALUES(?,?,?,?,?,?,?,?,?,?,?)
        """, (dni, categoria, tipo, periodo, clean(detalle), clean(observacion), original, str(path), ext, now_txt(), uploaded_by))
        con.commit()
    return str(path)


def inferir_tipo_desde_ruta(path: Path):
    texto = str(path).lower()
    reglas = [("util", "Utilidad"), ("vacacion", "Vacaciones"), ("normal", "Normal"), ("cts", "CTS"), ("liquid", "Liquidación"), ("grat", "Gratificación"), ("constancia", "Constancia Gratificación"), ("contrato", "Contrato de Trabajo"), ("sst", "Reglamento de SST"), ("interno", "Reglamento Interno"), ("conducta", "Código de Conducta"), ("politica", "Políticas"), ("políticas", "Políticas"), ("comunicado", "Comunicados")]
    for clave, tipo in reglas:
        if clave in texto:
            return tipo
    return "Otros"


def inferir_periodo_desde_ruta(path: Path):
    texto = str(path)
    m = re.search(r"(20\d{2})[-_ ]?(0[1-9]|1[0-2])", texto)
    if m: return f"{m.group(1)}-{m.group(2)}"
    m = re.search(r"(0[1-9]|1[0-2])[-_ ]?(20\d{2})", texto)
    if m: return f"{m.group(2)}-{m.group(1)}"
    m = re.search(r"(20\d{2})", texto)
    if m: return m.group(1)
    return datetime.now(APP_TZ).strftime("%Y-%m")


def documento_ya_indexado(path: Path):
    with db() as con:
        return con.execute("SELECT 1 FROM documentos WHERE ruta_archivo=?", (str(path),)).fetchone() is not None


def extraer_texto_pdf(path: Path, max_paginas=2):
    """Extrae texto de las primeras páginas para detectar DNI dentro de la boleta."""
    if path.suffix.lower() != '.pdf' or PdfReader is None:
        return ''
    try:
        reader = PdfReader(str(path))
        partes = []
        for page in reader.pages[:max_paginas]:
            try:
                partes.append(page.extract_text() or '')
            except Exception:
                pass
        return '\n'.join(partes)[:8000]
    except Exception:
        return ''


def detectar_dni_en_archivo(path: Path, dni_obj=''):
    """Busca DNI primero en ruta/nombre y, si es PDF, también dentro del contenido."""
    dni_obj = normalizar_dni(dni_obj) if dni_obj else ''
    texto_ruta = str(path)
    if dni_obj and dni_obj in texto_ruta:
        return dni_obj, 'ruta/nombre'
    m = re.search(r"(?<!\d)(\d{8})(?!\d)", texto_ruta)
    if m:
        return m.group(1), 'ruta/nombre'
    texto_pdf = extraer_texto_pdf(path)
    if texto_pdf:
        if dni_obj and dni_obj in re.sub(r'\D', '', texto_pdf):
            return dni_obj, 'contenido PDF'
        patrones = [
            r"(?:DNI|D\.?N\.?I\.?|DOC(?:UMENTO)?|COD(?:IGO)?|IDENTIDAD)\s*[:º°#-]?\s*(\d{8})",
            r"(?<!\d)(\d{8})(?!\d)",
        ]
        for pat in patrones:
            mm = re.search(pat, texto_pdf, flags=re.I)
            if mm:
                return normalizar_dni(mm.group(1)), 'contenido PDF'
    return '', ''


def detalle_auto_desde_ruta(path: Path):
    txt = str(path).lower()
    if 'semanal' in txt or 'semana' in txt:
        return 'Boleta semanal - Importado automáticamente desde carpeta'
    if 'mensual' in txt or 'mes' in txt:
        return 'Boleta mensual - Importado automáticamente desde carpeta'
    return 'Importado automáticamente desde carpeta'


def registrar_archivo_existente(path: Path, dni: str, tipo: str, uploaded_by="auto", fuente_dni='ruta/nombre'):
    uploaded_by = marca_carga(uploaded_by)
    if documento_ya_indexado(path): return False
    ext = path.suffix.lower()
    if ext not in EXT_ALLOWED: return False
    label, icon, categoria = ALL_TIPOS.get(tipo, (tipo, "📄", "personal"))
    dni = normalizar_dni(dni) if categoria != "empresa" else ""
    periodo = inferir_periodo_desde_ruta(path)
    detalle = detalle_auto_desde_ruta(path)
    obs = f"Detectado automáticamente por {fuente_dni}. Ruta: {path.parent}"
    with db() as con:
        con.execute("""
        INSERT INTO documentos(dni,categoria,tipo,periodo,detalle,observacion,archivo_nombre,ruta_archivo,extension,fecha_subida,uploaded_by)
        VALUES(?,?,?,?,?,?,?,?,?,?,?)
        """, (dni, categoria, tipo, periodo, detalle, obs, path.name, str(path), ext, now_txt(), uploaded_by))
        con.commit()
    return True


def sincronizar_documentos_carpeta(dni=None, devolver_resumen=False):
    # Detecta documentos desde DOCUMENTOS_PRIZE_AUTO, incluyendo:
    # DOCUMENTOS DE PAGO / BOLETAS NORMAL / SEMANAL.
    # Si el DNI no está en el nombre, lee el PDF e intenta encontrarlo dentro del texto.
    asegurar_carpetas_documentales()
    base_dirs = []
    for b in [DOCUMENTOS_BASE_DIR, BASE_DIR / "documentos_auto"]:
        if b.exists() and b.is_dir() and b not in base_dirs:
            base_dirs.append(b)
    total = 0
    revisados = omitidos = duplicados = sin_dni = sin_trabajador = 0
    dni_obj = normalizar_dni(dni) if dni else ""
    for base in base_dirs:
        for path in base.rglob("*"):
            if not path.is_file() or path.suffix.lower() not in EXT_ALLOWED:
                continue
            revisados += 1
            if documento_ya_indexado(path):
                duplicados += 1; continue
            tipo = inferir_tipo_desde_ruta(path)
            categoria = ALL_TIPOS.get(tipo, ("", "", "personal"))[2]
            dni_detectado, fuente = detectar_dni_en_archivo(path, dni_obj)
            if categoria != "empresa" and not dni_detectado:
                sin_dni += 1; omitidos += 1; continue
            if dni_obj and categoria != "empresa" and dni_detectado != dni_obj:
                omitidos += 1; continue
            if categoria != "empresa":
                trab = get_trabajador(dni_detectado)
                if not trab or int(trab['activo'] or 0) != 1:
                    sin_trabajador += 1; omitidos += 1; continue
            try:
                if registrar_archivo_existente(path, dni_detectado, tipo, uploaded_by="auto carpeta local", fuente_dni=fuente or 'carpeta'):
                    total += 1
            except Exception:
                omitidos += 1
    resumen = {'nuevos': total, 'revisados': revisados, 'duplicados': duplicados, 'omitidos': omitidos, 'sin_dni': sin_dni, 'sin_trabajador': sin_trabajador, 'base': str(DOCUMENTOS_BASE_DIR)}
    return resumen if devolver_resumen else total

