FINAL_UI_PATCH_JS = '\n<script id="final-ui-camera-patch">\n(function(){\n  window.scanReqStream = window.scanReqStream || null;\n  window.scanReqCount = window.scanReqCount || 0;\n  window.limpiarDniReq = window.limpiarDniReq || function(v){ return String(v||\'\').replace(/\\D/g,\'\').slice(-8); };\n  window.activarCamaraReq = async function(){\n    const v = document.getElementById(\'videoScanReq\');\n    const msg = document.getElementById(\'scanCamMsg\');\n    const modo = document.getElementById(\'modo_scan_req\');\n    try{\n      if(!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia){ alert(\'El navegador no permite cámara. Use HTTPS/Render, localhost o lector USB.\'); return false; }\n      if(window.scanReqStream){ window.scanReqStream.getTracks().forEach(t=>t.stop()); }\n      window.scanReqStream = await navigator.mediaDevices.getUserMedia({video:{facingMode:{ideal:\'environment\'}, width:{ideal:1280}, height:{ideal:720}}, audio:false});\n      if(v){ v.srcObject = window.scanReqStream; v.style.display = \'block\'; v.muted = true; await v.play().catch(()=>{}); }\n      if(msg){ msg.style.display=\'none\'; msg.innerHTML=\'\'; }\n      if(modo){ modo.value=\'Cámara celular / web\'; }\n      iniciarLecturaBarcodeReq();\n      return true;\n    }catch(e){\n      let ayuda=\'No se pudo activar cámara. En celular debe ser HTTPS/Render. En PC local usa http://127.0.0.1:5000.\';\n      if(e && (e.name===\'NotAllowedError\'||e.name===\'PermissionDeniedError\')) ayuda=\'Permite la cámara desde el candado del navegador y vuelve a presionar Activar cámara.\';\n      alert(ayuda); if(msg){ msg.style.display=\'block\'; msg.innerHTML=ayuda; } return false;\n    }\n  };\n  window.apagarCamaraReq = function(){\n    if(window._scanReqTimer){ clearInterval(window._scanReqTimer); window._scanReqTimer=null; }\n    if(window.scanReqStream){ window.scanReqStream.getTracks().forEach(t=>t.stop()); window.scanReqStream=null; }\n    const v=document.getElementById(\'videoScanReq\'); if(v){ v.pause(); v.srcObject=null; v.style.display=\'none\'; }\n    const m=document.getElementById(\'scanCamMsg\'); if(m){ m.style.display=\'block\'; m.innerHTML=\'Cámara detenida. Puedes usar lector USB o volver a activar cámara.\'; }\n  };\n  if(!window.agregarDniLocalReq) window.agregarDniLocalReq = function(valor){\n    const i=document.getElementById(\'dni_scan_req\'); const raw = valor || (i ? i.value : \'\'); const dni=window.limpiarDniReq(raw);\n    if(dni.length!==8){ alert(\'DNI debe tener 8 dígitos.\'); return false; }\n    if(i){ i.value=dni; i.focus(); i.select(); }\n    window.scanReqCount = (window.scanReqCount||0)+1;\n    const c=document.getElementById(\'cntLeidos\'); if(c) c.innerText=\'Leídos: \'+window.scanReqCount;\n    const r=document.getElementById(\'scan_result_req\'); if(r) r.value=\'DNI \'+dni+\' agregado. Nuevo/Reingresante listo para guardar.\';\n    const box=document.getElementById(\'listaScanReq\'); if(box){ const row=document.createElement(\'div\'); row.innerHTML=\'<b>\'+dni+\'</b><span>Listo para guardar / completar ficha</span><small>\'+new Date().toLocaleTimeString()+\'</small>\'; box.prepend(row); }\n    return true;\n  };\n  function iniciarLecturaBarcodeReq(){\n    const v=document.getElementById(\'videoScanReq\'); const msg=document.getElementById(\'scanCamMsg\');\n    if(window._scanReqTimer){ clearInterval(window._scanReqTimer); }\n    if(!(\'BarcodeDetector\' in window)){ if(msg){ msg.style.display=\'block\'; msg.innerHTML=\'Cámara activa. Si tu navegador no lee códigos automáticamente, escanea con lector USB o digita el DNI y presiona ENTER.\'; } return; }\n    let detector; try{ detector = new BarcodeDetector({formats:[\'qr_code\',\'code_128\',\'code_39\',\'ean_13\',\'pdf417\']}); }catch(e){ return; }\n    let ultimo=\'\';\n    window._scanReqTimer=setInterval(async()=>{ try{ if(!v || !v.videoWidth) return; const codes=await detector.detect(v); if(!codes || !codes.length) return; const val=(codes[0].rawValue||\'\').replace(/\\D/g,\'\'); const dni=val.slice(-8); if(dni.length===8 && dni!==ultimo){ ultimo=dni; window.agregarDniLocalReq(dni); } }catch(e){} },900);\n  }\n  document.addEventListener(\'DOMContentLoaded\', function(){ const i=document.getElementById(\'dni_scan_req\'); if(i && !i.dataset.finalPatch){ i.dataset.finalPatch=\'1\'; i.addEventListener(\'keydown\', function(e){ if(e.key===\'Enter\'){ e.preventDefault(); window.agregarDniLocalReq(); } }); } });\n})();\n</script>\n'

@app.after_request
def aplicar_parche_ui_final_definitivo(response):
    try:
        if response.content_type and 'text/html' in response.content_type.lower():
            html_txt = response.get_data(as_text=True)
            if 'final-ui-patch-definitivo' not in html_txt:
                bloque_css = "<style id='final-ui-patch-definitivo'>" + FINAL_UI_PATCH_CSS + "</style>"
                if '</head>' in html_txt:
                    html_txt = html_txt.replace('</head>', bloque_css + '</head>', 1)
                else:
                    html_txt = bloque_css + html_txt
            if 'final-ui-camera-patch' not in html_txt:
                if '</body>' in html_txt:
                    html_txt = html_txt.replace('</body>', FINAL_UI_PATCH_JS + '</body>', 1)
                else:
                    html_txt += FINAL_UI_PATCH_JS
            response.set_data(html_txt)
            response.headers['Content-Length'] = str(len(response.get_data()))
    except Exception as e:
        print('Parche UI final no aplicado:', e)
    return response



